import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.*;

class CSVFormatTest {

    @Test
    void testWithIgnoreSurroundingSpaces() {
        CSVFormat original = CSVFormat.DEFAULT;
        assertFalse(original.getIgnoreSurroundingSpaces());

        CSVFormat modified = original.withIgnoreSurroundingSpaces();
        assertNotNull(modified);
        assertTrue(modified.getIgnoreSurroundingSpaces());

        // Calling withIgnoreSurroundingSpaces again on the modified instance returns the same instance (idempotent)
        CSVFormat modifiedAgain = modified.withIgnoreSurroundingSpaces();
        assertSame(modified, modifiedAgain);

        // Check that original instance is unchanged
        assertFalse(original.getIgnoreSurroundingSpaces());
    }
}
